module top_module(
    input [7:0] a,
    input [7:0] b,
    input clk,
    input rst,
    output reg [8:0] sum
);reg [8:0] unused_carry;

always @ (posedge clk) begin
    if (rst) begin
        sum <= 0;
        unused_carry <= 0;
    end else begin
        {unused_carry, sum} <= a + b + unused_carry;
    end
end

endmodule
